;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

if(! loading) events.push2(1, 2, 3, 4);

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6, 7]

;-------------------------------------------------------------------------------
*event_1
;[exp] true
*event_2
;[exp] true
*event_3
;[exp] true
*event_4
;[exp] true

@callbattle gameover=true
@delevent
@jump storage=&'o.森の城塞１Ｆ.mapFile' target=*_dropMembersItem

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] WAY == "n"

@jump target=*_card_check cond='! game.party.hasItem(o.信徒の称号・月)'
@jump target=*_card_check cond='! game.party.hasItem(o.信徒の称号・星)'
@jump target=*_card_check cond='! game.party.hasItem(o.信徒の称号・雲)'
@jump target=*_card_check cond='! game.party.hasItem(o.信徒の称号・海)'
@jump target=*_card_check cond='! game.party.hasItem(o.信徒の称号・太陽)'
@notice text="You have successfully completed your arduous training. I will grant you the privilege of meeting the guru."
@eval exp='game.party.ejectItem(o.信徒の称号・月)'
@eval exp='game.party.ejectItem(o.信徒の称号・星)'
@eval exp='game.party.ejectItem(o.信徒の称号・雲)'
@eval exp='game.party.ejectItem(o.信徒の称号・海)'
@eval exp='game.party.ejectItem(o.信徒の称号・太陽)'
@wait time=800
@se f=fence
@switchfence x=5 y=1 way=n mode=open
@delevent
[eventoff]

*_card_check
@notice text="The door will not open for those who have not completed the five training exercises."

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger

@notice text="Audience Chamber"

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] true

@delevent
@jump storage="main11.scn" target=*fortress

[eventoff]
